// /frontend/src/components/Chatbot.jsx
import React, { useEffect, useRef, useState } from "react";

export default function Chatbot() {
  const [messages, setMessages] = useState([
    { role: "assistant", content: "Hey! Ask me about the weather, routes, or anything else." }
  ]);
  const [input, setInput] = useState("");
  const [busy, setBusy] = useState(false);
  const endRef = useRef(null);

  useEffect(() => {
    endRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, busy]);

  const send = async () => {
    const text = input.trim();
    if (!text || busy) return;
    setInput("");
    setMessages((m) => [...m, { role: "user", content: text }]);
    setBusy(true);

    try {
      // 👉 Plug in your backend here:
      // const res = await fetch("/api/chat", { method:"POST", headers:{ "Content-Type":"application/json" }, body: JSON.stringify({ message: text })});
      // const data = await res.json();
      // const reply = data?.reply ?? "…";
      // TEMP local response:
      const reply = demoReply(text);
      await new Promise(r => setTimeout(r, 350)); // tiny delay for feel
      setMessages((m) => [...m, { role: "assistant", content: reply }]);
    } catch (e) {
      setMessages((m) => [...m, { role: "assistant", content: "Sorry—chat service is unavailable." }]);
    } finally {
      setBusy(false);
    }
  };

  const onKey = (e) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      send();
    }
  };

  return (
    <div className="rounded-2xl backdrop-blur-xl bg-black/40 ring-1 ring-white/10 p-4 h-[70vh] flex flex-col">
      <div className="text-sm opacity-80 mb-2">Chatbot</div>

      <div className="flex-1 overflow-y-auto space-y-3 pr-1">
        {messages.map((m, i) => (
          <div key={i} className={`max-w-[85%] ${m.role === "assistant" ? "self-start" : "self-end"}`}>
            <div className={`px-3 py-2 rounded-2xl ${
              m.role === "assistant" ? "bg-white/10" : "bg-purple-500/30"
            }`}>
              <div className="whitespace-pre-wrap text-sm">{m.content}</div>
            </div>
          </div>
        ))}
        {busy && <div className="text-xs opacity-60">Assistant is typing…</div>}
        <div ref={endRef} />
      </div>

      <div className="mt-3 flex gap-2">
        <textarea
          className="flex-1 bg-white/10 rounded-xl px-3 py-2 text-sm outline-none resize-none h-10"
          placeholder="Type a message…"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={onKey}
        />
        <button
          onClick={send}
          disabled={busy || !input.trim()}
          className="px-4 py-2 rounded-xl bg-white/15 ring-1 ring-white/10 disabled:opacity-50"
        >
          Send
        </button>
      </div>
    </div>
  );
}

// lightweight local reply — swap with your /api/chat later
function demoReply(q) {
  const t = q.toLowerCase();
  if (t.includes("rain") || t.includes("umbrella")) return "Looks like scattered showers later today. Keep an umbrella handy just in case.";
  if (t.includes("snow")) return "Snow chances are low right now, but temps overnight dip near freezing.";
  if (t.includes("wind")) return "Breezy this afternoon—gusts 15–20 mph.";
  if (t.includes("radar")) return "Open the Radar section to see live precip. Heavy rain shows red; snow shows blue.";
  return "Got it! I can answer weather questions, or just say 'radar', 'snow', 'wind' to try me.";
}
